// Valida input e monta URL do snapshot. HTTP nos nós seguintes (fora do Code task runner de 60s).
const PANEL_BASE = 'https://longflatworm-n8n.cloudfy.live/webhook';
const input = $json || {};
const userId = String(input.user_id || '');
const codes = Array.isArray(input.client_codes) ? input.client_codes.map(s => String(s).trim()).filter(Boolean) : [];
const origin_lat = Number.isFinite(+input.origin_lat) ? +input.origin_lat : -23.6884;
const origin_lng = Number.isFinite(+input.origin_lng) ? +input.origin_lng : -46.6178;
const source = ['reactivation','prospect','mixed'].includes(input.source) ? input.source : 'reactivation';
const snapshot_url = PANEL_BASE + '/castor-panel-snapshot' + (userId ? '?userId=' + encodeURIComponent(userId) : '');
const route_url = PANEL_BASE + '/castor-panel-route';
return [{ json: { user_id: userId, codes, origin_lat, origin_lng, source, snapshot_url, route_url, missing_codes: !codes.length } }];

const params = $('Prepare params').first().json;
if (params.missing_codes) return [{ json: { ok: false, halt: true, data: null, error: 'client_codes vazio' } }];
const resp = $json || {};
if (resp.error && !resp.ok) return [{ json: { ok: false, halt: true, data: null, error: 'snapshot_failed: ' + (resp.error.message || resp.error) } }];
if (!resp || resp.ok === false) return [{ json: { ok: false, halt: true, data: null, error: 'snapshot_failed: ' + ((resp && resp.error) || 'snapshot indisponivel') } }];
const snap = resp.data || {};
const munIdx = Object.create(null);
for (const m of (snap.municipios || [])) { if (m.lat != null && m.lng != null) munIdx[m.mun + '|' + m.est] = m; }
const byCode = Object.create(null);
for (const c of (snap.clientes || [])) byCode[c.cliente_codigo] = c;
const stops = [];
const skipped = [];
for (const code of params.codes) {
  const c = byCode[code];
  if (!c) { skipped.push({ code, reason: 'cliente nao encontrado' }); continue; }
  const m = munIdx[(c.a1_mun || '').toUpperCase() + '|' + (c.a1_est || '').toUpperCase()];
  if (!m) { skipped.push({ code, reason: 'sem coordenadas no CC2010' }); continue; }
  stops.push({ cliente_codigo: code, lat: m.lat, lng: m.lng, name: c.a1_nome || c.a1_nreduz || code });
}
if (!stops.length) return [{ json: { ok: false, halt: true, data: { skipped }, error: 'nenhum cliente com coordenadas' } }];
return [{ json: { ok: true, halt: false, stops, skipped, route_url: params.route_url, route_body: { user_id: params.user_id, stops, origin_lat: params.origin_lat, origin_lng: params.origin_lng, source: params.source } } }];

const ctx = $('Build stops').first().json;
const resp = $json || {};
if (resp.error && !resp.ok) return [{ json: { ok: false, data: { skipped: ctx.skipped || [] }, error: 'route_failed: ' + (resp.error.message || resp.error) } }];
if (!resp || resp.ok === false) return [{ json: { ok: false, data: { skipped: ctx.skipped || [] }, error: 'route_failed: ' + ((resp && resp.error) || 'route falhou') } }];
return [{ json: { ok: true, data: Object.assign({}, resp.data, { skipped: ctx.skipped || [] }), error: null } }];
